export interface User {
  id: number;
  name: string;
  email: string;
  createdAt: string;
}

let nextId = 1;
const store = new Map<number, User>();

export function createUser(name: string, email: string): User {
  const user: User = {
    id: nextId++,
    name,
    email,
    createdAt: new Date().toISOString(),
  };
  store.set(user.id, user);
  return user;
}

export function getUser(id: number): User | null {
  return store.get(id) ?? null;
}

export function listUsers(): User[] {
  return [...store.values()].sort((a, b) => a.id - b.id);
}

export function updateUser(id: number, patch: Partial<Pick<User, 'name' | 'email'>>): User | null {
  const user = store.get(id);
  if (!user) return null;
  const updated = { ...user, ...patch };
  store.set(id, updated);
  return updated;
}

export function deleteUser(id: number): boolean {
  return store.delete(id);
}

import { parseArgs } from 'node:util';

export interface ListArgs {
  file: string;
  tag: string | null;
  activeOnly: boolean;
}

export function parseListArgs(argv: string[]): ListArgs {
  const { values, positionals } = parseArgs({
    args: argv,
    options: {
      tag: { type: 'string', short: 't' },
      active: { type: 'boolean', short: 'a' },
    },
    allowPositionals: true,
  });
  const file = positionals[0];
  if (!file) throw new Error('Usage: list <file> [--tag <tag>] [--active]');
  return {
    file,
    tag: values.tag ?? null,
    activeOnly: values.active ?? false,
  };
}

import { readFileSync } from 'node:fs';

export function readJsonFile<T>(path: string): T {
  let raw: string;
  try {
    raw = readFileSync(path, 'utf-8');
  } catch {
    throw new Error(`File not found: ${path}`);
  }
  try {
    return JSON.parse(raw) as T;
  } catch {
    throw new Error(`Invalid JSON in file: ${path}`);
  }
}

interface Item {
  name: string;
  tags: string[];
  active: boolean;
}

export function filterAndSort(
  items: Item[],
  opts: { tag: string | null; activeOnly: boolean }
): Item[] {
  let filtered = items;
  if (opts.tag) {
    const tag = opts.tag;
    filtered = filtered.filter(item => item.tags.includes(tag));
  }
  if (opts.activeOnly) {
    filtered = filtered.filter(item => item.active);
  }
  return filtered.sort((a, b) => a.name.localeCompare(b.name));
}

export function formatTable(items: Array<{ name: string; tags: string[]; active: boolean }>): string {
  if (items.length === 0) return '(no items)';
  const rows = items.map(item => ({
    name: item.name.padEnd(24),
    tags: item.tags.join(', ').padEnd(30),
    active: item.active ? 'yes' : 'no',
  }));
  const header = 'NAME                    TAGS                           ACTIVE';
  const sep = '-'.repeat(header.length);
  const lines = rows.map(r => `${r.name} ${r.tags} ${r.active}`);
  return [header, sep, ...lines].join('\n');
}

export function writeStdout(text: string): void {
  try {
    process.stdout.write(text + '\n');
  } catch (err) {
    if ((err as NodeJS.ErrnoException).code !== 'EPIPE') throw err;
  }
}

export type Listener<T> = (event: T) => void;

export class EventEmitter<Events extends Record<string, unknown>> {
  private readonly listeners = new Map<keyof Events, Set<Listener<unknown>>>();

  on<K extends keyof Events>(event: K, listener: Listener<Events[K]>): void {
    let set = this.listeners.get(event);
    if (!set) {
      set = new Set();
      this.listeners.set(event, set);
    }
    set.add(listener as Listener<unknown>);
  }

  off<K extends keyof Events>(event: K, listener: Listener<Events[K]>): void {
    this.listeners.get(event)?.delete(listener as Listener<unknown>);
  }

  once<K extends keyof Events>(event: K, listener: Listener<Events[K]>): void {
    const wrapper: Listener<Events[K]> = (e) => {
      this.off(event, wrapper);
      listener(e);
    };
    this.on(event, wrapper);
  }

  emit<K extends keyof Events>(event: K, data: Events[K]): void {
    const set = this.listeners.get(event);
    if (!set) return;
    for (const listener of [...set]) {
      (listener as Listener<Events[K]>)(data);
    }
  }
}

export function inRange(value: number, min: number, max: number): boolean {
  return value >= min && value < max;
}

export function deepClone<T>(value: T): T {
  return JSON.parse(JSON.stringify(value)) as T;
}
